public class JDBCTest08 {
    public static void main(String[] args) {
        String name;
        String password;
        String relName="";
        boolean sign=false;
        Scanner in=new Scanner(System.in);
        System.out.println("用户名：");
        name=in.next();
        System.out.println("密码：");
        password=in.next();
