### vue-router

设置路由配置，编写路由守卫

在src目录下创建一个router目录，然后在router目录下创建一个index.js文件

在index.js文件中编写路由配置，这时候我们还没有写组件，我们可以构思好组件，对于单体页面来说，一般需要一个主页面，在这个主页面中包括一个侧边栏或导航栏，通过这个导航栏我们可以跳转到指定组件，另外我们在完成了主界面后还可以设计一下登录页面。登录页面应该是和主页面同级的。可以覆盖主页面。

```java
import { createRouter, createWebHistory } from 'vue-router'

const routes = [
  {
    path: '/login',
    name: 'Login',
    component: () => import('@/views/login/Login.vue')
  },
  {
    path: '/',
    name: 'Layout',
    component: () => import('@/views/layout/Layout.vue'),
    redirect: '/employee',
    children: [
      {
        path: 'dashboard',
        name: 'Dashboard',
        component: () => import('@/views/dashboard/Dashboard.vue'),
        meta: { title: '首页' }
      },
      {
        path: 'employee',
        name: 'Employee',
        component: () => import('@/views/employee/Employee.vue'),
        meta: { title: '员工管理' }
      },
      {
        path: 'employee/add',
        name: 'EmployeeAdd',
        component: () => import('@/views/employee/EmployeeForm.vue'),
        meta: { title: '新增员工' }
      },
      {
        path: 'employee/edit/:id',
        name: 'EmployeeEdit',
        component: () => import('@/views/employee/EmployeeForm.vue'),
        meta: { title: '编辑员工' }
      },
      {
        path: 'department',
        name: 'Department',
        component: () => import('@/views/department/Department.vue'),
        meta: { title: '部门管理' }
      },
      {
        path: 'position',
        name: 'Position',
        component: () => import('@/views/position/Position.vue'),
        meta: { title: '岗位管理' }
      },
      {
        path: 'attendance',
        name: 'Attendance',
        component: () => import('@/views/attendance/Attendance.vue'),
        meta: { title: '考勤管理' }
      },
      {
        path: 'salary',
        name: 'Salary',
        component: () => import('@/views/salary/Salary.vue'),
        meta: { title: '薪酬管理' }
      },
      {
        path: 'profile',
        name: 'Profile',
        component: () => import('@/views/profile/Profile.vue'),
        meta: { title: '个人中心' }
      }
    ]
  }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

// 路由守卫
router.beforeEach((to, from, next) => {
  //如果没有token或者是token过期直接跳转到登录页面
  const isAuthenticated = localStorage.getItem('token')
  console.log("taken: "+isAuthenticated);

  if (to.name !== 'Login' && !isAuthenticated) {
    next({ name: 'Login' })
  }
   else {
    next()
  }
})

export default router
```

