        meta: { title: '首页' }
      },
      {
        path: 'employee',
        name: 'Employee',
        component: () => import('@/views/employee/Employee.vue'),
        meta: { title: '员工管理' }
      },
      {
        path: 'employee/add',
        name: 'EmployeeAdd',
        component: () => import('@/views/employee/EmployeeForm.vue'),
        meta: { title: '新增员工' }
      },
      {
        path: 'employee/edit/:id',
        name: 'EmployeeEdit',
        component: () => import('@/views/employee/EmployeeForm.vue'),
        meta: { title: '编辑员工' }
      },
      {
        path: 'department',
        name: 'Department',
        component: () => import('@/views/department/Department.vue'),
        meta: { title: '部门管理' }
      },
      {
        path: 'position',
        name: 'Position',
        component: () => import('@/views/position/Position.vue'),
        meta: { title: '岗位管理' }
      },
      {
        path: 'attendance',
        name: 'Attendance',
        component: () => import('@/views/attendance/Attendance.vue'),
        meta: { title: '考勤管理' }
      },
      {
        path: 'salary',
        name: 'Salary',
        component: () => import('@/views/salary/Salary.vue'),
